1	//! Multi-threaded zerocopy runtime — message-moving
2	//! infrastructure.
3	//!
4	//! Pairs with [`crate::actor_manager`], which owns the actor
5	//! model surface ([`ActorZC`], [`ContextZC`], [`ActorManager`]).
6	//! This module is one consumer of that surface; future
7	//! transports (M:N scheduler, alternative channel types, …)
8	//! would be peers.
9	//!
10	//! Responsibilities held here:
11	//!
12	//! - Owns the [`Pool<S>`]; spawns actor threads; wires
13	//!   per-actor `mpsc` channels; runs the warmup / measure /
14	//!   shutdown lifecycle.
15	//! - Knows nothing about "seeds", named lookups, or what a
16	//!   benchmark is. Initial messages are passed to
17	//!   [`RuntimeZC::run`] directly by the app; the runtime
18	//!   delivers them after spawn / before warmup, then forgets.
19	//! - Drains the manager via [`ActorManager::take_actors`] +
20	//!   [`ActorManager::probe_name_prefix`] when `run` is called.
21	//!
22	//! Two run entry points on [`RuntimeZC`]:
23	//!
24	//! - [`RuntimeZC::run`] — `tprobe`-instrumented; returns
25	//!   `(count, TProbe)` per actor. Used by the `goalzc` binary.
26	//! - [`RuntimeZC::run_no_probe`] — probe-free; returns `count`
27	//!   per actor. Used by the `goalzc-crit` criterion bench so
28	//!   measurement is not contaminated by probe overhead.
29	//!
30	//! Lifecycle inside `run` / `run_no_probe`:
31	//!
32	//! - Drain actors from the Manager.
33	//! - Build per-actor channels.
34	//! - Spawn one thread per actor, optionally pinned.
35	//! - Deliver `initial_messages` over the senders.
36	//! - Sleep `warmup`.
37	//! - Send `ClearProbe` to every actor.
38	//! - Sleep `measurement`.
39	//! - Send `Shutdown` to every actor.
40	//! - Drop main-thread senders so the channels close.
41	//! - Join, return per-actor results.
42	//!
43	//! Drain invariant: by the time the join completes, every
44	//! [`PooledMsg`] that was ever in flight has been dropped, so
45	//! `pool.free_len() == pool.size()`.
46	
47	use std::sync::mpsc::{self, Receiver, Sender};
48	use std::thread::{self, JoinHandle};
49	use std::time::Duration;
50	
51	use crate::actor_manager::{ActorManager, ActorZC, ContextZC};
52	use crate::pool::{BufRefStore, MutexLifo, Pool, PoolError, PooledMsg};
53	use tprobe::TProbe;
54	
55	/// Internal channel payload.
56	///
57	/// - `User(msg)` — caller-visible traffic.
58	/// - `ClearProbe` — runtime injects at warmup → measurement
59	///   boundary so the report only sees steady-state data.
60	/// - `Shutdown` — runtime injects after the measurement
61	///   window; actor exits its `recv` loop on receipt.
62	enum SignalZC<S: BufRefStore> {
63	    User(PooledMsg<S>),
64	    ClearProbe,
65	    Shutdown,
66	}
67	
68	/// Multi-threaded zerocopy runtime — message-moving
69	/// infrastructure.
70	///
71	/// - Owns the [`Pool<S>`] (cloned cheaply to each actor
72	///   thread).
73	/// - Spawns threads, wires channels, runs the warmup /
74	///   measure / shutdown lifecycle.
75	/// - Knows nothing about "seeds", named lookups, or what's
76	///   being measured. Initial messages come in as a parameter
77	///   to `run` and are delivered after spawn / before warmup.
78	/// - Generic over the store backend `S` so concurrency
79	///   strategies can be swapped and benchmarked. Default
80	///   [`MutexLifo`].
81	pub struct RuntimeZC<S: BufRefStore = MutexLifo> {
82	    pool: Pool<S>,
83	}
84	
85	impl<S: BufRefStore + 'static> RuntimeZC<S> {
86	    /// Build a runtime that draws buffers from `pool`.
87	    ///
88	    /// - The runtime stores a cheap `Arc` clone; the caller
89	    ///   keeps the original handle so it can build initial
90	    ///   messages or inspect (`free_len`, `size`).
91	    pub fn new(pool: Pool<S>) -> Self {
92	        Self { pool }
93	    }
94	
95	    /// Borrow the runtime's pool handle.
96	    pub fn pool(&self) -> &Pool<S> {
97	        &self.pool
98	    }
99	
100	    /// Drain the manager's actors, run with `tprobe`
101	    /// instrumentation.
102	    ///
103	    /// - Each actor thread owns a [`TProbe`] recording per-
104	    ///   `handle_message` latency at `inner=1`.
105	    /// - `initial_messages` are delivered after thread spawn,
106	    ///   before warmup.
107	    /// - Returns `(count, probe)` per actor in id order.
108	    pub fn run(
109	        &mut self,
110	        mgr: &mut ActorManager<S>,
111	        initial_messages: Vec<(u32, PooledMsg<S>)>,
112	        warmup: Duration,
113	        measurement: Duration,
114	        pin_cores: &[usize],
115	    ) -> Vec<(u64, TProbe)> {
116	        self.run_inner(
117	            mgr,
118	            initial_messages,
119	            warmup,
120	            measurement,
121	            pin_cores,
122	            actor_loop_probe::<S>,
123	        )
124	    }
125	
126	    /// Same orchestration as [`RuntimeZC::run`], minus the
127	    /// per-message `TProbe` calls in the hot loop.
128	    ///
129	    /// - Used by the `goalzc-crit` criterion bench so the
130	    ///   measurement is probe-clean.
131	    /// - The lesson learned from `goal2-crit`'s probe
132	    ///   contamination: keeping a probe-free path on the
133	    ///   runtime from the start avoids the trap of a bench
134	    ///   that secretly measures `work + tprobe`.
135	    pub fn run_no_probe(
136	        &mut self,
137	        mgr: &mut ActorManager<S>,
138	        initial_messages: Vec<(u32, PooledMsg<S>)>,
139	        warmup: Duration,
140	        measurement: Duration,
141	        pin_cores: &[usize],
142	    ) -> Vec<u64> {
143	        self.run_inner(
144	            mgr,
145	            initial_messages,
146	            warmup,
147	            measurement,
148	            pin_cores,
149	            actor_loop_no_probe::<S>,
150	        )
151	    }
152	
153	    /// Shared orchestration body.
154	    ///
155	    /// - Drains the manager, builds channels, spawns one
156	    ///   thread per actor, delivers initial messages, runs
157	    ///   the warmup / measure / shutdown lifecycle, joins,
158	    ///   and returns per-actor results.
159	    /// - Per-thread work is delegated to `actor_loop`, a
160	    ///   function pointer (`ActorLoopFn<S, R>`) so this method
161	    ///   monomorphizes per `R` without the closure / `Fn`-bound
162	    ///   overhead.
163	    fn run_inner<R: Send + 'static>(
164	        &mut self,
165	        mgr: &mut ActorManager<S>,
166	        initial_messages: Vec<(u32, PooledMsg<S>)>,
167	        warmup: Duration,
168	        measurement: Duration,
169	        pin_cores: &[usize],
170	        actor_loop: ActorLoopFn<S, R>,
171	    ) -> Vec<R> {
172	        let actors = mgr.take_actors();
173	        let n = actors.len();
174	        let pool = self.pool.clone();
175	        let probe_name_prefix = mgr.probe_name_prefix().to_string();
176	
177	        let mut senders: Vec<Sender<SignalZC<S>>> = Vec::with_capacity(n);
178	        let mut receivers: Vec<Option<Receiver<SignalZC<S>>>> = Vec::with_capacity(n);
179	        for _ in 0..n {
180	            let (tx, rx) = mpsc::channel();
181	            senders.push(tx);
182	            receivers.push(Some(rx));
183	        }
184	
185	        let mut handles: Vec<JoinHandle<R>> = Vec::with_capacity(n);
186	        for (id, actor) in actors.into_iter().enumerate() {
187	            #[allow(clippy::unwrap_used)]
188	            // OK: receivers[id] was set to `Some(...)` in the loop above.
189	            let rx = receivers[id].take().unwrap();
190	            let peers: Vec<Sender<SignalZC<S>>> = senders.to_vec();
191	            let probe_name = format!("{}.actor{}", probe_name_prefix, id);
192	            let pin_target = if pin_cores.is_empty() {
193	                None
194	            } else {
195	                Some(pin_cores[id % pin_cores.len()])
196	            };
197	            let actor_pool = pool.clone();
198	            let h = thread::Builder::new()
199	                .name(format!("actor-zc-{id}"))
200	                .spawn(move || {
201	                    tprobe::pin::pin_current(pin_target);
202	                    actor_loop(actor, rx, peers, actor_pool, probe_name)
203	                })
204	                .expect("failed to spawn actor thread");
205	            handles.push(h);
206	        }
207	
208	        for (dst, msg) in initial_messages {
209	            #[allow(clippy::unwrap_used)]
210	            // OK: receivers are alive (threads just spawned); a send
211	            //   failure indicates an immediate thread panic at startup
212	            //   which the join below surfaces with a clearer message.
213	            senders[dst as usize].send(SignalZC::User(msg)).unwrap();
214	        }
215	
216	        thread::sleep(warmup);
217	        for tx in &senders {
218	            let _ = tx.send(SignalZC::ClearProbe);
219	        }
220	
221	        thread::sleep(measurement);
222	        for tx in &senders {
223	            let _ = tx.send(SignalZC::Shutdown);
224	        }
225	        drop(senders);
226	
227	        let mut results = Vec::with_capacity(n);
228	        for h in handles {
229	            results.push(h.join().expect("actor thread panicked"));
230	        }
231	        results
232	    }
233	}
234	
235	/// Function-pointer type for the per-thread actor loop, used
236	/// by [`RuntimeZC::run_inner`]. `fn(...) -> R` is `Copy +
237	/// Send + Sync`, which keeps the orchestration scaffold
238	/// generic without closure / `Fn`-bound complications.
239	type ActorLoopFn<S, R> = fn(
240	    Box<dyn ActorZC<S> + Send>,
241	    Receiver<SignalZC<S>>,
242	    Vec<Sender<SignalZC<S>>>,
243	    Pool<S>,
244	    String,
245	) -> R;
246	
247	/// `ContextZC` impl used inside each actor thread.
248	///
249	/// - Holds borrowed references to the actor's peer senders
250	///   and the shared pool.
251	/// - `get_msg` delegates to [`Pool::get_msg`].
252	/// - `send` ships a `PooledMsg` over the appropriate channel;
253	///   on closed channel the message drops back to the pool.
254	struct MultiCtxZC<'a, S: BufRefStore> {
255	    senders: &'a [Sender<SignalZC<S>>],
256	    pool: &'a Pool<S>,
257	}
258	
259	impl<S: BufRefStore> ContextZC<S> for MultiCtxZC<'_, S> {
260	    fn get_msg(&mut self, size: usize) -> Result<PooledMsg<S>, PoolError> {
261	        self.pool.get_msg(size)
262	    }
263	
264	    fn send(&mut self, dst_id: u32, msg: PooledMsg<S>) {
265	        // Ignored Err contains the un-sent SignalZC::User(msg);
266	        // dropping it returns the buffer to the pool.
267	        let _ = self.senders[dst_id as usize].send(SignalZC::User(msg));
268	    }
269	}
270	
271	/// Per-thread loop with `tprobe` instrumentation.
272	///
273	/// - One scope per `handle_message` (`inner=1`).
274	/// - `Signal::User` records.
275	/// - `Signal::ClearProbe` resets probe + count.
276	/// - `Signal::Shutdown` (or closed channel) exits.
277	fn actor_loop_probe<S: BufRefStore + 'static>(
278	    mut actor: Box<dyn ActorZC<S> + Send>,
279	    rx: Receiver<SignalZC<S>>,
280	    peers: Vec<Sender<SignalZC<S>>>,
281	    pool: Pool<S>,
282	    probe_name: String,
283	) -> (u64, TProbe) {
284	    let mut probe = TProbe::new(&probe_name);
285	    let mut count: u64 = 0;
286	    loop {
287	        match rx.recv() {
288	            Ok(SignalZC::User(msg)) => {
289	                let id = probe.start(0);
290	                let mut ctx = MultiCtxZC {
291	                    senders: &peers,
292	                    pool: &pool,
293	                };
294	                actor.handle_message(&mut ctx, &msg);
295	                probe.end(id);
296	                drop(msg);
297	                count += 1;
298	            }
299	            Ok(SignalZC::ClearProbe) => {
300	                probe.clear();
301	                count = 0;
302	            }
303	            Ok(SignalZC::Shutdown) | Err(_) => break,
304	        }
305	    }
306	    (count, probe)
307	}
308	
309	/// Per-thread loop with no probe involvement.
310	///
311	/// - Identical to [`actor_loop_probe`] minus `probe.start` /
312	///   `probe.end` / `probe.clear`.
313	/// - `_probe_name` is unused but kept in the signature so the
314	///   function pointer matches [`ActorLoopFn`] without
315	///   special-casing.
316	fn actor_loop_no_probe<S: BufRefStore + 'static>(
317	    mut actor: Box<dyn ActorZC<S> + Send>,
318	    rx: Receiver<SignalZC<S>>,
319	    peers: Vec<Sender<SignalZC<S>>>,
320	    pool: Pool<S>,
321	    _probe_name: String,
322	) -> u64 {
323	    let mut count: u64 = 0;
324	    loop {
325	        match rx.recv() {
326	            Ok(SignalZC::User(msg)) => {
327	                let mut ctx = MultiCtxZC {
328	                    senders: &peers,
329	                    pool: &pool,
330	                };
331	                actor.handle_message(&mut ctx, &msg);
332	                drop(msg);
333	                count += 1;
334	            }
335	            Ok(SignalZC::ClearProbe) => {
336	                count = 0;
337	            }
338	            Ok(SignalZC::Shutdown) | Err(_) => break,
339	        }
340	    }
341	    count
342	}
343	
344	#[cfg(test)]
345	mod tests {
346	    use super::*;
347	    use crate::pool::Pool;
348	
349	    /// Generic ping-pong actor reusable across `S` choices.
350	    /// On each message: get a same-sized reply buffer, send
351	    /// to the configured peer, drop the inbound `PooledMsg`
352	    /// (returns its buffer to the pool).
353	    struct PingPong {
354	        peer: u32,
355	    }
356	
357	    impl<S: BufRefStore> ActorZC<S> for PingPong {
358	        fn handle_message(&mut self, ctx: &mut dyn ContextZC<S>, msg: &[u8]) {
359	            let reply = ctx.get_msg(msg.len()).expect("get_msg should succeed");
360	            ctx.send(self.peer, reply);
361	        }
362	    }
363	
364	    /// Two-actor ping-pong drives traffic and shuts down
365	    /// cleanly; both actors record nonzero counts.
366	    #[test]
367	    fn ping_pong_runs_and_shuts_down() {
368	        let pool: Pool = Pool::new(64, 4);
369	        let mut rt = RuntimeZC::new(pool.clone());
370	        let mut mgr = ActorManager::new("test.zc");
371	        let a = mgr.add(PingPong { peer: 1 });
372	        let _b = mgr.add(PingPong { peer: 0 });
373	        let initial = vec![(a, pool.get_msg(8).expect("seed"))];
374	        let results = rt.run(
375	            &mut mgr,
376	            initial,
377	            Duration::from_millis(40),
378	            Duration::from_millis(40),
379	            &[],
380	        );
381	        assert_eq!(results.len(), 2);
382	        let total: u64 = results.iter().map(|(c, _)| *c).sum();
383	        assert!(total > 0, "expected nonzero throughput, got count={total}");
384	    }
385	
386	    /// After `run` returns, every buffer the pool ever
387	    /// handed out has come back. Tests the drain story
388	    /// across the channel-close path.
389	    #[test]
390	    fn pool_is_full_after_shutdown() {
391	        let pool: Pool = Pool::new(64, 4);
392	        let mut rt = RuntimeZC::new(pool.clone());
393	        let mut mgr = ActorManager::new("test.drain");
394	        let a = mgr.add(PingPong { peer: 1 });
395	        let _b = mgr.add(PingPong { peer: 0 });
396	        let initial = vec![(a, pool.get_msg(8).expect("seed"))];
397	        let _ = rt.run(
398	            &mut mgr,
399	            initial,
400	            Duration::from_millis(20),
401	            Duration::from_millis(20),
402	            &[],
403	        );
404	        assert_eq!(
405	            pool.free_len(),
406	            pool.size(),
407	            "all buffers should return to pool after shutdown"
408	        );
409	    }
410	
411	    /// `run_no_probe` orchestrates identically and returns
412	    /// per-actor counts (no probes). Validates that the
413	    /// probe-clean path runs the same workload.
414	    #[test]
415	    fn run_no_probe_returns_counts() {
416	        let pool: Pool = Pool::new(64, 4);
417	        let mut rt = RuntimeZC::new(pool.clone());
418	        let mut mgr = ActorManager::new("test.np");
419	        let a = mgr.add(PingPong { peer: 1 });
420	        let _b = mgr.add(PingPong { peer: 0 });
421	        let initial = vec![(a, pool.get_msg(8).expect("seed"))];
422	        let results = rt.run_no_probe(
423	            &mut mgr,
424	            initial,
425	            Duration::from_millis(20),
426	            Duration::from_millis(20),
427	            &[],
428	        );
429	        assert_eq!(results.len(), 2);
430	        let total: u64 = results.iter().sum();
431	        assert!(total > 0, "expected nonzero throughput, got {total}");
432	        assert_eq!(
433	            pool.free_len(),
434	            pool.size(),
435	            "all buffers should return to pool after no-probe shutdown"
436	        );
437	    }
438	
439	    /// `Runtime::pool` exposes the caller's handle; the
440	    /// caller can build initial messages from it without
441	    /// holding a separate clone.
442	    #[test]
443	    fn runtime_pool_accessor_returns_same_handle() {
444	        let pool: Pool = Pool::new(32, 2);
445	        let rt = RuntimeZC::new(pool.clone());
446	        assert_eq!(rt.pool().msg_size(), 32);
447	        assert_eq!(rt.pool().size(), 2);
448	    }
449	}
